from temporalio import workflow
from datetime import timedelta

@workflow.defn
class ParentResearchWorkflow:
    @workflow.run
    async def run(self, topics: list[str]) -> list[str]:
        # Fan out — spawn one child workflow per topic in parallel
        handles = [
            await workflow.start_child_workflow(
                SingleTopicResearch,
                topic,
                id=f"research-{topic.lower().replace(' ', '-')}",
                task_queue="ai-agent-queue",
            )
            for topic in topics
        ]
        # Wait for all children to complete
        results = await asyncio.gather(*[h.result() for h in handles])
        return list(results)

@workflow.defn
class SingleTopicResearch:
    @workflow.run
    async def run(self, topic: str) -> str:
        outline = await workflow.execute_activity(
            generate_outline, topic,
            schedule_to_close_timeout=timedelta(minutes=2),
        )
        # ... further activities
        return outline
